mapper.select:
SELECT grp_cd, grp_nm, grp_desc, use_yn, sort_ord, created_at, created_by, updated_at, updated_by FROM tb_com_code_grp
AND grp_cd LIKE CONCAT('%', #{condition.grpCd}, '%')
AND grp_nm LIKE CONCAT('%', #{condition.grpNm}, '%')
AND use_yn = #{condition.useYn}
ORDER BY sort_ord, grp_cd LIMIT #{offset}, #{limit}

SELECT grp_cd, grp_nm, grp_desc, use_yn, sort_ord, created_at, created_by, updated_at, updated_by
FROM tb_com_code_grp
WHERE grp_cd = #{grpCd}

mapper.update:
UPDATE tb_com_code_grp
SET grp_nm = #{grpNm}, grp_desc = #{grpDesc}, use_yn = #{useYn}, sort_ord = #{sortOrd}, updated_by = #{updatedBy}
WHERE grp_cd = #{grpCd}

mapper.select:
SELECT grp_cd, code, code_nm, code_desc, use_yn, sort_ord, attr1, attr2, attr3, created_at, created_by, updated_at, updated_by
FROM tb_com_code
WHERE grp_cd = #{grpCd}
ORDER BY sort_ord, code
LIMIT #{offset}, #{limit}

SELECT grp_cd, code, code_nm, code_desc, use_yn, sort_ord, attr1, attr2, attr3, created_at, created_by, updated_at, updated_by
FROM tb_com_code
WHERE grp_cd = #{grpCd} AND code = #{code}

mapper.update:
UPDATE tb_com_code
SET code_nm = #{codeNm}, code_desc = #{codeDesc}, use_yn = #{useYn}, sort_ord = #{sortOrd},
    attr1 = #{attr1}, attr2 = #{attr2}, attr3 = #{attr3}, updated_by = #{updatedBy}
WHERE grp_cd = #{grpCd} AND code = #{code}
